// ─── Risk Scoring Engine (8 Dimensions) ───
// Weights from PhD spec: Event Severity (0.18), Source Confidence (0.10),
// Trade Exposure (0.18), Route Criticality (0.14), Commodity Sensitivity (0.12),
// Escalation Momentum (0.10), Customs Relevance (0.12), Geophysical Impact (0.06).

const WEIGHTS = {
  eventSeverity: 0.18,
  sourceConfidence: 0.10,
  tradeExposure: 0.18,
  routeCriticality: 0.14,
  commoditySensitivity: 0.12,
  escalationMomentum: 0.10,
  customsRelevance: 0.12,
  geophysicalImpact: 0.06,
};

const SEVERITY_KEYWORDS = {
  critical: { score: 100, words: ['attack', 'war', 'missile', 'bomb', 'invasion', 'nuclear', 'blockade', 'sanction'] },
  high:     { score: 75,  words: ['escalation', 'tension', 'threat', 'crisis', 'disruption', 'collision', 'grounding'] },
  moderate: { score: 50,  words: ['warning', 'alert', 'protest', 'strike', 'delay', 'shortage', 'volatility'] },
  low:      { score: 25,  words: ['concern', 'uncertainty', 'discuss', 'monitor', 'review', 'report'] },
};

const ROUTE_KEYWORDS = {
  'Suez Canal':       { criticality: 0.95, words: ['suez', 'red sea', 'bab el mandeb'] },
  'Strait of Hormuz': { criticality: 0.90, words: ['hormuz', 'strait of hormuz'] },
  'Panama Canal':     { criticality: 0.85, words: ['panama', 'panama canal'] },
  'Taiwan Strait':    { criticality: 0.85, words: ['taiwan strait', 'taiwan'] },
  'Malacca Strait':   { criticality: 0.80, words: ['malacca'] },
  'Gibraltar':        { criticality: 0.70, words: ['gibraltar'] },
};

const COMMODITY_KEYWORDS = {
  'Semiconductors':       { sensitivity: 0.95, words: ['semiconductor', 'chip', 'silicon', 'tsmc'] },
  'Oil & Gas':            { sensitivity: 0.90, words: ['oil', 'gas', 'lng', 'crude', 'energy'] },
  'Grain & Agriculture':  { sensitivity: 0.75, words: ['grain', 'wheat', 'corn', 'agriculture', 'food', 'fertilizer'] },
  'Pharmaceuticals':      { sensitivity: 0.70, words: ['pharma', 'medicine', 'drug'] },
  'Consumer Goods':       { sensitivity: 0.60, words: ['consumer', 'retail', 'goods', 'container'] },
};

const CUSTOMS_KEYWORDS = ['tariff', 'customs', 'duty', 'import', 'export', 'trade policy', 'quota', 'origin', 'hs code', 'classification', 'valuation', 'clearance', 'smuggling', 'counterfeit', 'contraband'];

function matchKeywords(text, wordList) {
  const lower = text.toLowerCase();
  return wordList.some(w => lower.includes(w));
}

function scoreArticle(article) {
  const text = `${article.title || ''} ${article.seendate || ''}`;
  const lower = text.toLowerCase();

  // 1. Event Severity
  let eventSeverity = 10;
  for (const [, cfg] of Object.entries(SEVERITY_KEYWORDS)) {
    if (matchKeywords(text, cfg.words)) { eventSeverity = cfg.score; break; }
  }

  // 2. Source Confidence (based on domain reputation — simplified)
  const domain = (article.domain || '').toLowerCase();
  const trustedDomains = ['reuters.com', 'apnews.com', 'bbc.com', 'aljazeera.com', 'ft.com', 'economist.com', 'wsj.com', 'nytimes.com', 'bloomberg.com'];
  const sourceConfidence = trustedDomains.some(d => domain.includes(d)) ? 85 : 50;

  // 3. Trade Exposure (keyword density)
  const tradeWords = ['trade', 'import', 'export', 'bilateral', 'deficit', 'surplus', 'commerce', 'shipping', 'freight', 'port'];
  const tradeHits = tradeWords.filter(w => lower.includes(w)).length;
  const tradeExposure = Math.min(100, tradeHits * 20);

  // 4. Route Criticality
  let routeCriticality = 0;
  let matchedRoute = null;
  for (const [name, cfg] of Object.entries(ROUTE_KEYWORDS)) {
    if (matchKeywords(text, cfg.words)) { routeCriticality = cfg.criticality * 100; matchedRoute = name; break; }
  }

  // 5. Commodity Sensitivity
  let commoditySensitivity = 0;
  let matchedCommodity = null;
  for (const [name, cfg] of Object.entries(COMMODITY_KEYWORDS)) {
    if (matchKeywords(text, cfg.words)) { commoditySensitivity = cfg.sensitivity * 100; matchedCommodity = name; break; }
  }

  // 6. Escalation Momentum (presence of escalation language)
  const escalationWords = ['escalat', 'intensif', 'worsen', 'spread', 'surge', 'spike', 'unprecedented'];
  const escalationMomentum = escalationWords.some(w => lower.includes(w)) ? 75 : 15;

  // 7. Customs Relevance
  const customsHits = CUSTOMS_KEYWORDS.filter(w => lower.includes(w)).length;
  const customsRelevance = Math.min(100, customsHits * 25);

  // 8. Geophysical/Climate Impact
  const geoWords = ['earthquake', 'tsunami', 'hurricane', 'typhoon', 'flood', 'drought', 'volcanic', 'wildfire', 'cyclone'];
  const geophysicalImpact = geoWords.some(w => lower.includes(w)) ? 70 : 5;

  // Compute weighted score
  const dimensions = { eventSeverity, sourceConfidence, tradeExposure, routeCriticality, commoditySensitivity, escalationMomentum, customsRelevance, geophysicalImpact };
  const riskScore = Math.round(
    WEIGHTS.eventSeverity * eventSeverity +
    WEIGHTS.sourceConfidence * sourceConfidence +
    WEIGHTS.tradeExposure * tradeExposure +
    WEIGHTS.routeCriticality * routeCriticality +
    WEIGHTS.commoditySensitivity * commoditySensitivity +
    WEIGHTS.escalationMomentum * escalationMomentum +
    WEIGHTS.customsRelevance * customsRelevance +
    WEIGHTS.geophysicalImpact * geophysicalImpact
  );

  // Classify level
  let level = 'Low';
  if (riskScore >= 85) level = 'Critical';
  else if (riskScore >= 70) level = 'High';
  else if (riskScore >= 50) level = 'Elevated';
  else if (riskScore >= 25) level = 'Moderate';

  return {
    ...article,
    riskScore,
    riskLevel: level,
    dimensions,
    matchedRoute,
    matchedCommodity,
    scoredAt: new Date().toISOString(),
  };
}

// Process each article from the merged GDELT results
const articles = $input.item.json.articles || [];
const scored = articles.map(scoreArticle).sort((a, b) => b.riskScore - a.riskScore);

return { json: { scoredArticles: scored, totalArticles: scored.length, scoredAt: new Date().toISOString() } };

// Merge all 3 GDELT fetches into a single articles array
const customs = $('GDELT — Customs & Trade Intelligence').first().json;
const routes = $('GDELT — Critical Trade Routes').first().json;
const commodities = $('GDELT — Commodity Disruptions').first().json;

const allArticles = [
  ...(customs?.articles || []),
  ...(routes?.articles || []),
  ...(commodities?.articles || []),
];

// Deduplicate by URL
const seen = new Set();
const deduped = allArticles.filter(a => {
  if (!a.url || seen.has(a.url)) return false;
  seen.add(a.url);
  return true;
});

return { json: { articles: deduped, totalRaw: allArticles.length, totalDeduped: deduped.length } };

// Filter articles by minimum risk threshold and prepare final output
const MIN_RISK_SCORE = 25;
const data = $input.item.json;
const filtered = (data.scoredArticles || []).filter(a => a.riskScore >= MIN_RISK_SCORE);

// Group by risk level
const byLevel = { Critical: [], High: [], Elevated: [], Moderate: [] };
for (const a of filtered) {
  if (byLevel[a.riskLevel]) byLevel[a.riskLevel].push(a);
}

return {
  json: {
    alerts: filtered,
    summary: {
      total: filtered.length,
      critical: byLevel.Critical.length,
      high: byLevel.High.length,
      elevated: byLevel.Elevated.length,
      moderate: byLevel.Moderate.length,
    },
    processedAt: new Date().toISOString(),
  }
};
